+  FiShoppingCart, FiCreditCard, FiCamera, FiUser
+} from 'react-icons/fi';
+
+const getProductImage = (category) => {
+  const images = {
+    'Dairy': 'https://images.unsplash.com/photo-1550583724-b2692b5b2b4f?w=200&h=200&fit=crop',
+    'Bakery': 'https://images.unsplash.com/photo-1509440159596-0249088772ff?w=200&h=200&fit=crop',
+    'Beverages': 'https://images.unsplash.com/photo-1543253687-c931c8e01820?w=200&h=200&fit=crop',
+    'Fruits': 'https://images.unsplash.com/photo-1619566636858-adf3ef46400b?w=200&h=200&fit=crop',
+    'Vegetables': 'https://images.unsplash.com/photo-1597362921503-75c3da9e4feb?w=200&h=200&fit=crop',
+    'Meat': 'https://images.unsplash.com/photo-1607623814075-e51df1bdc82f?w=200&h=200&fit=crop',
+    'Snacks': 'https://images.unsplash.com/photo-1621939514649-280e2ee25f60?w=200&h=200&fit=crop',
+    'Grains': 'https://images.unsplash.com/photo-1586201375761-83865001e31c?w=200&h=200&fit=crop'
+  };
+  return images[category] || 'https://images.unsplash.com/photo-1542838132-92c53300491e?w=200&h=200&fit=crop';
+};
+
+const CashierScreen = () => {
+  const [cart, setCart] = useState([]);
+  const [searchQuery, setSearchQuery] = useState('');
+  const [searchResults, setSearchResults] = useState([]);
+  const [discount, setDiscount] = useState(0);
+  const [taxRate, setTaxRate] = useState(15);
+  const [paymentMethod, setPaymentMethod] = useState('cash');
+  const [cashGiven, setCashGiven] = useState('');
+  const [showCheckout, setShowCheckout] = useState(false);
+  const [loading, setLoading] = useState(false);
+
+  const searchInputRef = useRef(null);
+
+  useEffect(() => {
+    searchInputRef.current?.focus();
+  }, []);
+
+  useEffect(() => {
+    const timer = setTimeout(() => {
+      if (searchQuery.trim()) {
+        searchProducts();
+      } else {
+        setSearchResults([]);
+      }
+    }, 400);
+    return () => clearTimeout(timer);
+  }, [searchQuery]);
+
+  const searchProducts = async () => {
+    try {
+      const res = await api.get(`/products?search=${searchQuery}`);
+      const productsWithImages = res.data.map(p => ({
+        ...p,
+        image: getProductImage(p.category)
+      }));
+      setSearchResults(productsWithImages);
+    } catch (error) {
+      console.error('Search error:', error);
+    }
+  };
+
+  const addToCart = (product) => {
+    const existing = cart.find(item => item.id === product.id);
+    if (existing) {
+      setCart(cart.map(item =>
+        item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
+      ));
+    } else {
+      setCart([...cart, { ...product, quantity: 1 }]);
+    }
+    setSearchQuery('');
+    setSearchResults([]);
+    toast.success(`تمت إضافة ${product.name}`);
+  };
+
+  const updateQuantity = (id, delta) => {
+    setCart(cart.map(item => {
+      if (item.id === id) {
+        const newQty = item.quantity + delta;
+        return newQty > 0 ? { ...item, quantity: newQty } : null;
+      }
+      return item;
+    }).filter(Boolean));
+  };
+
+  const removeFromCart = (id) => {
+    setCart(cart.filter(item => item.id !== id));
+    toast.success('تم حذف المنتج');
+  };
+
+  const clearCart = () => {
+    if (cart.length > 0 && window.confirm('هل أنت متأكد من تفريغ العربة؟')) {
+      setCart([]);
+      setDiscount(0);
+      setShowCheckout(false);
+      toast.success('تم تفريغ العربة');
+    }
+  };
+
+  const subtotal = cart.reduce((sum, item) => sum + item.selling_price * item.quantity, 0);
+  const tax = (subtotal * taxRate) / 100;
+  const total = subtotal - discount + tax;
+  const change = cashGiven ? parseFloat(cashGiven) - total : 0;
+
+  const handleCheckout = async () => {
+    if (cart.length === 0) return toast.error('العربة فارغة');
+    if (paymentMethod === 'cash' && (!cashGiven || parseFloat(cashGiven) < total)) {
+      return toast.error('المبلغ المدفوع غير كاف');
+    }
+
+    setLoading(true);
+    try {
+      const transaction = {
+        items: cart.map(item => ({
+          product_id: item.id,
+          name: item.name,
+          quantity: item.quantity,
+          price: item.selling_price
+        })),
+        total,
+        tax,
+        discount,
+        payment_method: paymentMethod,
+        cash_given: paymentMethod === 'cash' ? parseFloat(cashGiven) : null,
+        change_due: paymentMethod === 'cash' ? change : 0,
+        cashier_name: 'كاشير' // سيأتي من Context لاحقاً
+      };
+      await api.post('/transactions', transaction);
+      toast.success('تمت المعاملة بنجاح');
+      clearCart();
+      setShowCheckout(false);
+    } catch (error) {
+      toast.error('فشلت المعاملة');
+    } finally {
+      setLoading(false);
+    }
+  };
+
+  return (
+    <div className="page-container">
+      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
+        {/* القسم الرئيسي - المنتجات والعربة */}
+        <div className="lg:col-span-2 space-y-6">
+          {/* بطاقة البحث */}
+          <div className="card">
+            <div className="card-header">
+              <h2>
+                <FiSearch className="text-blue-600" />
+                البحث عن منتجات
+              </h2>
+            </div>
+            <div className="card-content">
+              <div className="relative">
+                <FiSearch className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
+                <input
+                  ref={searchInputRef}
+                  type="text"
+                  placeholder="ابحث بالاسم أو الباركود..."
+                  className="input-field pr-10 text-lg"
+                  value={searchQuery}
+                  onChange={(e) => setSearchQuery(e.target.value)}
+                />
+              </div>
+
