+  };
+
+  // الحسابات
+  const subtotal = cart.reduce((sum, item) => sum + item.selling_price * item.quantity, 0);
+  const tax = (subtotal * taxRate) / 100;
+  const total = subtotal - discount + tax;
+  const change = cashGiven ? parseFloat(cashGiven) - total : 0;
+
+  // إتمام عملية البيع
+  const handleCheckout = async () => {
+    if (cart.length === 0) return toast.error('Cart empty');
+    if (paymentMethod === 'cash' && (!cashGiven || parseFloat(cashGiven) < total)) {
+      return toast.error('Insufficient cash');
+    }
+    setLoading(true);
+    try {
+      const transaction = {
+        items: cart.map(item => ({
+          product_id: item.id,
+          name: item.name,
+          quantity: item.quantity,
+          price: item.selling_price
+        })),
+        total,
+        tax,
+        discount,
+        payment_method: paymentMethod,
+        cash_given: paymentMethod === 'cash' ? parseFloat(cashGiven) : null,
+        change_due: paymentMethod === 'cash' ? change : 0,
+        cashier_name: 'Cashier'
+      };
+      await api.post('/transactions', transaction);
+      toast.success('Transaction completed');
+      clearCart();
+    } catch (error) {
+      toast.error('Checkout failed');
+    } finally {
+      setLoading(false);
+    }
+  };
+
+  // المنتجات المعروضة (نتائج البحث أو جميع المنتجات)
+  const displayedProducts = searchResults.length > 0 ? searchResults : products;
+
+  return (
+    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
+      {/* القسم الأيسر: متصفح المنتجات */}
+      <div className="lg:col-span-2 space-y-6">
+        <div className="card">
+          <div className="card-header">
+            <h2>Search Product</h2>
+          </div>
+          <div className="card-content">
+            <div className="relative">
+              <FiSearch className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
+              <input
+                ref={searchInputRef}
+                type="text"
+                placeholder="Barcode or Name"
+                className="w-full pl-12 pr-4 py-3 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
+                value={searchQuery}
+                onChange={(e) => setSearchQuery(e.target.value)}
+              />
+            </div>
+          </div>
+        </div>
+
+        {/* شبكة المنتجات (بطاقات) */}
+        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
+          {displayedProducts.map(product => (
+            <div
+              key={product.id}
+              onClick={() => addToCart(product)}
+              className="bg-white rounded-xl shadow-sm hover:shadow-md transition-shadow p-4 cursor-pointer border border-gray-100"
+            >
+              <img
+                src={product.image}
+                alt={product.name}
+                className="w-full h-32 object-cover rounded-lg mb-3"
+              />
+              <h3 className="font-medium text-gray-800">{product.name}</h3>
+              <p className="text-lg font-bold text-blue-600">${product.selling_price}</p>
+            </div>
+          ))}
+        </div>
+      </div>
+
+      {/* القسم الأيمن: سلة المشتريات */}
+      <div className="space-y-6">
+        <div className="card sticky top-24">
+          <div className="card-header">
+            <h2>Cart</h2>
+          </div>
+          <div className="card-content">
+            {cart.length === 0 ? (
+              <div className="text-center py-8 text-gray-500">Cart is empty</div>
+            ) : (
+              <>
+                <div className="space-y-4 max-h-96 overflow-auto">
+                  {cart.map(item => (
+                    <div key={item.id} className="flex items-center gap-3 border-b border-gray-100 pb-3">
+                      <img src={item.image} alt={item.name} className="w-12 h-12 rounded-lg object-cover" />
+                      <div className="flex-1">
+                        <p className="font-medium text-gray-800">{item.name}</p>
+                        <p className="text-sm text-gray-500">${item.selling_price} x {item.quantity}</p>
+                      </div>
+                      <p className="font-semibold">${(item.selling_price * item.quantity).toFixed(2)}</p>
+                      <div className="flex items-center gap-1">
+                        <button
+                          onClick={() => updateQuantity(item.id, -1)}
+                          className="w-7 h-7 flex items-center justify-center bg-gray-100 rounded-lg hover:bg-gray-200"
+                        >
+                          <FiMinus size={14} />
+                        </button>
+                        <span className="w-6 text-center">{item.quantity}</span>
+                        <button
+                          onClick={() => updateQuantity(item.id, 1)}
+                          className="w-7 h-7 flex items-center justify-center bg-blue-500 text-white rounded-lg hover:bg-blue-600"
+                        >
+                          <FiPlus size={14} />
+                        </button>
+                        <button
+                          onClick={() => removeFromCart(item.id)}
+                          className="w-7 h-7 flex items-center justify-center bg-red-100 text-red-600 rounded-lg hover:bg-red-200 ml-1"
+                        >
+                          <FiTrash2 size={14} />
+                        </button>
+                      </div>
