import { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import toast from 'react-hot-toast';
import { FiPlus, FiMinus, FiTrash2, FiSearch, FiX } from 'react-icons/fi';

const API_URL = 'http://localhost:5000/api';

const CashierScreen = () => {
  const [cart, setCart] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [discount, setDiscount] = useState(0);
  const [taxRate, setTaxRate] = useState(0);
  const [paymentMethod, setPaymentMethod] = useState('cash');
  const [cashGiven, setCashGiven] = useState('');
  const [changeDue, setChangeDue] = useState(0);
  const searchInputRef = useRef(null);

  useEffect(() => {
    searchInputRef.current?.focus();
  }, []);

  useEffect(() => {
    const delayDebounce = setTimeout(() => {
      if (searchQuery) {
        axios.get(`${API_URL}/products?search=${searchQuery}`)
          .then(res => setSearchResults(res.data))
          .catch(err => console.error(err));
      } else {
        setSearchResults([]);
      }
    }, 300);
    return () => clearTimeout(delayDebounce);
  }, [searchQuery]);

  const addToCart = (product) => {
    const existing = cart.find(item => item.id === product.id);
    if (existing) {
      setCart(cart.map(item =>
        item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
      ));
    } else {
      setCart([...cart, { ...product, quantity: 1 }]);
    }
    setSearchQuery('');
    setSearchResults([]);
    toast.success(`${product.name} added`);
  };

  const updateQuantity = (id, delta) => {
    setCart(cart.map(item => {
      if (item.id === id) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : null;
      }
      return item;
    }).filter(Boolean));
  };

  const removeFromCart = (id) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const clearCart = () => {
    setCart([]);
    setDiscount(0);
    setCashGiven('');
    setChangeDue(0);
  };

  const subtotal = cart.reduce((sum, item) => sum + item.selling_price * item.quantity, 0);
  const tax = (subtotal * taxRate) / 100;
  const total = subtotal - discount + tax;

  const handleCheckout = async () => {
    if (cart.length === 0) {
      toast.error('Cart is empty');
      return;
    }
    if (paymentMethod === 'cash') {
      const cash = parseFloat(cashGiven);
      if (isNaN(cash) || cash < total) {
        toast.error('Insufficient cash given');
        return;
      }
      setChangeDue(cash - total);
    }

    const transaction = {
      items: cart.map(item => ({
        product_id: item.id,
        name: item.name,
        quantity: item.quantity,
        price: item.selling_price
      })),
      total,
      tax,
      discount,
      payment_method: paymentMethod,
      cash_given: paymentMethod === 'cash' ? parseFloat(cashGiven) : null,
      change_due: paymentMethod === 'cash' ? changeDue : 0,
      cashier_name: 'Cashier'
    };

    try {
      await axios.post(`${API_URL}/transactions`, transaction);
      toast.success('Transaction completed');
      clearCart();
    } catch (err) {
      toast.error('Checkout failed');
      console.error(err);
    }
  };

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'F1') { e.preventDefault(); searchInputRef.current?.focus(); }
      if (e.key === 'F2') { e.preventDefault(); handleCheckout(); }
      if (e.key === 'F3') { e.preventDefault(); clearCart(); }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [cart, total, cashGiven, paymentMethod, discount, taxRate]);

  return (
    <div className="flex flex-col lg:flex-row gap-6">
      <div className="lg:w-2/3 bg-white dark:bg-gray-800 rounded-lg shadow p-4">
        <h2 className="text-2xl font-bold mb-4 dark:text-white">Current Sale</h2>
        <div className="mb-4">
          <div className="relative">
            <input
              ref={searchInputRef}
              type="text"
              placeholder="Search products by name or barcode (F1)"
              className="w-full p-3 pl-10 border rounded-lg dark:bg-gray-700 dark:text-white"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            <FiSearch className="absolute left-3 top-4 text-gray-400" />
          </div>
          {searchResults.length > 0 && (
            <div className="absolute z-10 mt-1 w-full max-w-md bg-white dark:bg-gray-800 border rounded-lg shadow-lg">
              {searchResults.map(product => (
                <div
                  key={product.id}
                  className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 cursor-pointer flex justify-between"
                  onClick={() => addToCart(product)}
                >
                  <span>{product.name}</span>
                  <span className="font-bold">${product.selling_price}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="overflow-auto max-h-96">
          <table className="w-full">
            <thead>
              <tr className="border-b dark:border-gray-700">
                <th className="text-left py-2 dark:text-white">Item</th>
                <th className="text-left dark:text-white">Price</th>
                <th className="text-left dark:text-white">Qty</th>
                <th className="text-left dark:text-white">Total</th>
                <th></th>
              </tr>
            </thead>
            <tbody>
              {cart.map(item => (
                <tr key={item.id} className="border-b dark:border-gray-700">
                  <td className="py-2 dark:text-white">{item.name}</td>
                  <td className="dark:text-white">${item.selling_price.toFixed(2)}</td>
                  <td>
                    <div className="flex items-center">
                      <button onClick={() => updateQuantity(item.id, -1)} className="p-1 bg-gray-200 dark:bg-gray-700 rounded-l"><FiMinus /></button>
                      <span className="px-2 dark:text-white">{item.quantity}</span>
                      <button onClick={() => updateQuantity(item.id, 1)} className="p-1 bg-gray-200 dark:bg-gray-700 rounded-r"><FiPlus /></button>
                    </div>
                  </td>
                  <td className="dark:text-white">${(item.selling_price * item.quantity).toFixed(2)}</td>
                  <td><button onClick={() => removeFromCart(item.id)} className="text-red-500"><FiTrash2 /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {cart.length > 0 && (
          <button onClick={clearCart} className="mt-4 bg-red-500 text-white px-4 py-2 rounded-lg flex items-center">
            <FiX className="mr-2" /> Clear Cart (F3)
          </button>
        )}
      </div>

      <div className="lg:w-1/3 bg-white dark:bg-gray-800 rounded-lg shadow p-4">
        <h2 className="text-2xl font-bold mb-4 dark:text-white">Totals</h2>
        <div className="space-y-2 mb-4">
          <div className="flex justify-between dark:text-white"><span>Subtotal:</span><span>${subtotal.toFixed(2)}</span></div>
          <div className="flex justify-between items-center dark:text-white">
            <span>Discount ($):</span>
            <input type="number" value={discount} onChange={(e) => setDiscount(parseFloat(e.target.value) || 0)} className="w-24 p-1 border rounded dark:bg-gray-700 dark:text-white" />
          </div>
          <div className="flex justify-between items-center dark:text-white">
            <span>Tax (%):</span>
            <input type="number" value={taxRate} onChange={(e) => setTaxRate(parseFloat(e.target.value) || 0)} className="w-24 p-1 border rounded dark:bg-gray-700 dark:text-white" />
          </div>
          <div className="flex justify-between font-bold text-xl dark:text-white"><span>Total:</span><span>${total.toFixed(2)}</span></div>
        </div>

        <div className="mb-4">
          <label className="block dark:text-white mb-1">Payment Method</label>
          <select value={paymentMethod} onChange={(e) => setPaymentMethod(e.target.value)} className="w-full p-2 border rounded dark:bg-gray-700 dark:text-white">
            <option value="cash">Cash</option>
            <option value="card">Card</option>
          </select>
        </div>

        {paymentMethod === 'cash' && (
          <div className="mb-4">
            <label className="block dark:text-white mb-1">Cash Given</label>
            <input type="number" value={cashGiven} onChange={(e) => setCashGiven(e.target.value)} className="w-full p-2 border rounded dark:bg-gray-700 dark:text-white" />
            {changeDue > 0 && <div className="mt-2 text-green-600 dark:text-green-400">Change: ${changeDue.toFixed(2)}</div>}
          </div>
        )}

        <button onClick={handleCheckout} className="w-full bg-blue-600 text-white py-3 rounded-lg text-lg font-bold hover:bg-blue-700">
          Checkout (F2)
        </button>
      </div>
    </div>
  );
};

export default CashierScreen;
